1	use crate::config;
2	use cor24_emulator::{EmulatorCore, StopReason};
3	use gloo::timers::callback::Timeout;
4	use std::collections::VecDeque;
5	use web_sys::HtmlDivElement;
6	use yew::prelude::*;
7	
8	const PROMPT: &str = "      ";
9	
10	/// Execution batch size per tick (instructions).
11	const BATCH_SIZE: u64 = 50_000;
12	
13	/// Tick interval in milliseconds.
14	const TICK_MS: u32 = 25;
15	
16	pub enum Msg {
17	    KeyDown(KeyboardEvent),
18	    Init,
19	    Tick,
20	}
21	
22	/// Command counter — when the parent bumps the counter, we act.
23	#[derive(Properties, PartialEq)]
24	pub struct ReplPanelProps {
25	    /// Bumped by parent to trigger a reset.
26	    #[prop_or_default]
27	    pub reset_seq: u32,
28	    /// Text to feed as a demo program (set when demo_seq changes).
29	    #[prop_or_default]
30	    pub feed_text: AttrValue,
31	    /// Bumped by parent when feed_text should be consumed.
32	    #[prop_or_default]
33	    pub feed_seq: u32,
34	    /// S2 switch state.
35	    #[prop_or_default]
36	    pub s2_on: bool,
37	    /// Callback to report hardware state each tick: (led_on, last_tx, last_rx).
38	    #[prop_or_default]
39	    pub on_hw_state: Callback<(bool, Option<u8>, Option<u8>)>,
40	}
41	
42	pub struct ReplPanel {
43	    emulator: EmulatorCore,
44	    output: Vec<String>,
45	    input: String,
46	    running: bool,
47	    halted: bool,
48	    uart_rx_queue: VecDeque<u8>,
49	    /// Partial line buffer for UART output that hasn't ended with '\n' yet.
50	    partial_line: String,
51	    _tick_handle: Option<Timeout>,
52	    output_ref: NodeRef,
53	    panel_ref: NodeRef,
54	    needs_focus: bool,
55	    /// Track which reset_seq we last processed.
56	    last_reset_seq: u32,
57	    /// Track which feed_seq we last processed.
58	    last_feed_seq: u32,
59	    /// Last TX byte seen.
60	    last_tx: Option<u8>,
61	    /// Last RX byte seen.
62	    last_rx: Option<u8>,
63	}
64	
65	impl ReplPanel {
66	    fn schedule_tick(ctx: &Context<Self>) -> Timeout {
67	        let link = ctx.link().clone();
68	        Timeout::new(TICK_MS, move || link.send_message(Msg::Tick))
69	    }
70	
71	    fn scroll_to_bottom(&self) {
72	        if let Some(el) = self.output_ref.cast::<HtmlDivElement>() {
73	            el.set_scroll_top(el.scroll_height());
74	        }
75	    }
76	
77	    /// Load the pre-assembled APL binary and start the emulator.
78	    fn load_apl_binary(&mut self) {
79	        let binary = config::APL_BINARY;
80	        self.emulator.hard_reset();
81	        self.emulator.set_uart_tx_busy_cycles(0);
82	        self.emulator.load_program(0, binary);
83	        self.emulator.load_program_extent(binary.len() as u32);
84	        self.emulator.set_pc(0);
85	        self.emulator.resume();
86	        self.running = true;
87	        self.halted = false;
88	        self.output.clear();
89	        self.partial_line.clear();
90	        self.uart_rx_queue.clear();
91	        self.last_tx = None;
92	        self.last_rx = None;
93	    }
94	
95	    /// Feed bytes from the RX queue into the emulator UART while it's ready.
96	    fn feed_uart_bytes(&mut self) {
97	        while !self.uart_rx_queue.is_empty() {
98	            let status = self.emulator.read_byte(0xFF0101);
99	            if status & 0x01 != 0 {
100	                break; // RX buffer full, try again next tick
101	            }
102	            if let Some(byte) = self.uart_rx_queue.pop_front() {
103	                self.emulator.send_uart_byte(byte);
104	                self.last_rx = Some(byte);
105	            }
106	        }
107	    }
108	
109	    /// Collect UART output from the emulator and append to the output buffer.
110	    fn collect_uart(&mut self) {
111	        let uart = self.emulator.get_uart_output();
112	        if uart.is_empty() {
113	            return;
114	        }
115	        let uart = uart.to_string();
116	        self.emulator.clear_uart_output();
117	
118	        // Track last TX byte
119	        if let Some(b) = uart.bytes().last() {
120	            self.last_tx = Some(b);
121	        }
122	
123	        // Split on newlines, handling partial lines across ticks.
124	        for ch in uart.chars() {
125	            if ch == '\n' {
126	                self.output.push(std::mem::take(&mut self.partial_line));
127	            } else if ch != '\r' {
128	                self.partial_line.push(ch);
129	            }
130	        }
131	    }
132	
133	    /// Queue text to be sent to the interpreter line-by-line.
134	    fn feed_program_text(&mut self, text: &str) {
135	        for line in text.lines() {
136	            let trimmed = line.trim();
137	            if trimmed.is_empty() {
138	                continue;
139	            }
140	            for b in trimmed.bytes() {
141	                self.uart_rx_queue.push_back(b);
142	            }
143	            self.uart_rx_queue.push_back(b'\n');
144	        }
145	    }
146	}
147	
148	impl Component for ReplPanel {
149	    type Message = Msg;
150	    type Properties = ReplPanelProps;
151	
152	    fn create(ctx: &Context<Self>) -> Self {
153	        ctx.link().send_message(Msg::Init);
154	        let mut emulator = EmulatorCore::new();
155	        emulator.set_uart_tx_busy_cycles(0);
156	        Self {
157	            emulator,
158	            output: vec!["APL / COR24 Environment".to_string(), String::new()],
159	            input: String::new(),
160	            running: false,
161	            halted: false,
162	            uart_rx_queue: VecDeque::new(),
163	            partial_line: String::new(),
164	            _tick_handle: None,
165	            output_ref: NodeRef::default(),
166	            panel_ref: NodeRef::default(),
167	            needs_focus: false,
168	            last_reset_seq: 0,
169	            last_feed_seq: 0,
170	            last_tx: None,
171	            last_rx: None,
172	        }
173	    }
174	
175	    fn changed(&mut self, ctx: &Context<Self>, _old_props: &Self::Properties) -> bool {
176	        let props = ctx.props();
177	
178	        // Handle reset command
179	        if props.reset_seq != self.last_reset_seq {
180	            self.last_reset_seq = props.reset_seq;
181	            self.load_apl_binary();
182	            self.needs_focus = true;
183	            if self._tick_handle.is_none() {
184	                self._tick_handle = Some(Self::schedule_tick(ctx));
185	            }
186	        }
187	
188	        // Handle feed text command
189	        if props.feed_seq != self.last_feed_seq {
190	            self.last_feed_seq = props.feed_seq;
191	            self.feed_program_text(&props.feed_text);
192	            self.needs_focus = true;
193	        }
194	
195	        // S2 switch — use emulator API (active-low hardware)
196	        self.emulator.set_button_pressed(props.s2_on);
197	
198	        true
199	    }
200	
201	    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
202	        match msg {
203	            Msg::Init => {
204	                self.load_apl_binary();
205	                self._tick_handle = Some(Self::schedule_tick(ctx));
206	                true
207	            }
208	            Msg::Tick => {
209	                if !self.running || self.halted {
210	                    return false;
211	                }
212	
213	                self.feed_uart_bytes();
214	                let result = self.emulator.run_batch(BATCH_SIZE);
215	                self.collect_uart();
216	
217	                if matches!(result.reason, StopReason::Halted) {
218	                    self.halted = true;
219	                    self.running = false;
220	                }
221	
222	                if self.running && !self.halted {
223	                    self._tick_handle = Some(Self::schedule_tick(ctx));
224	                }
225	
226	                // Report hardware state to parent (LED is active-low)
227	                let led_on = self.emulator.is_led_on();
228	                ctx.props()
229	                    .on_hw_state
230	                    .emit((led_on, self.last_tx, self.last_rx));
231	
232	                true
233	            }
234	            Msg::KeyDown(e) => {
235	                // Let modifier combos (Cmd-C, Ctrl-V, etc.) pass through to browser
236	                if e.meta_key() || e.ctrl_key() || e.alt_key() {
237	                    return false;
238	                }
239	                let key = e.key();
240	                match key.as_str() {
241	                    "Enter" => {
242	                        e.prevent_default();
243	                        // Show the input line in output
244	                        let line = format!("{PROMPT}{}", self.input);
245	                        self.output.push(line);
246	                        // Queue input bytes for the emulator's UART
247	                        for b in self.input.bytes() {
248	                            self.uart_rx_queue.push_back(b);
249	                        }
250	                        self.uart_rx_queue.push_back(b'\n');
251	                        self.input.clear();
252	                        true
253	                    }
254	                    "Backspace" => {
255	                        e.prevent_default();
256	                        self.input.pop();
257	                        true
258	                    }
259	                    _ => {
260	                        if key.len() == 1 {
261	                            e.prevent_default();
262	                            let ch = key.chars().next().unwrap();
263	                            if ch.is_ascii_graphic() || ch == ' ' {
264	                                self.input.push(ch);
265	                                return true;
266	                            }
267	                        }
268	                        false
269	                    }
270	                }
271	            }
272	        }
273	    }
274	
275	    fn rendered(&mut self, _ctx: &Context<Self>, first_render: bool) {
276	        self.scroll_to_bottom();
277	        if (first_render || self.needs_focus)
278	            && let Some(el) = self.panel_ref.cast::<HtmlDivElement>()
279	        {
280	            let _ = el.focus();
281	            self.needs_focus = false;
282	        }
283	    }
284	
285	    fn view(&self, ctx: &Context<Self>) -> Html {
286	        let onkeydown = ctx.link().callback(Msg::KeyDown);
287	
288	        html! {
289	            <div class="repl-panel" tabindex="0" {onkeydown} ref={self.panel_ref.clone()}>
290	                <div class="repl-output" ref={self.output_ref.clone()}>
291	                    { for self.output.iter().map(|line| html! {
292	                        <div class="repl-line">{ line }</div>
293	                    })}
294	                    // Show partial line if the emulator is mid-output
295	                    if !self.partial_line.is_empty() {
296	                        <div class="repl-line">{ &self.partial_line }</div>
297	                    }
298	                    <div class="repl-input-line">
299	                        <span class="repl-prompt">{ PROMPT }</span>
300	                        <span class="repl-input-text">{ &self.input }</span>
301	                        <span class="repl-cursor">{"\u{2588}"}</span>
302	                    </div>
303	                </div>
304	            </div>
305	        }
306	    }
307	}
